#!/bin/bash
echo "→ Schreibe app.py v3.0 (Phasen + Reset)..."
echo '' | base64 -d > /opt/charge-goertz/app.py
echo "✓ app.py: $(wc -c < /opt/charge-goertz/app.py) Bytes"
sudo systemctl restart charge-goertz
sleep 2
systemctl is-active --quiet charge-goertz && echo "✓ Service laeuft!" || echo "FEHLER"
echo "Test:"
curl -s http://localhost:5000/api/energy/1 | python3 -m json.tool 2>/dev/null | head -20
